"use client";

import Link from "next/link";
import { useEffect, useRef, useState } from "react";

function safeId() {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }
  return Math.random().toString(36).slice(2, 11);
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function renderEntityLinks(text, entities, bookId) {
  if (!text || !Array.isArray(entities) || entities.length === 0 || !bookId) {
    return text;
  }
  const entries = entities
    .map((entry) => ({
      name: typeof entry?.name === "string" ? entry.name.trim() : "",
      slug: typeof entry?.slug === "string" ? entry.slug.trim() : "",
    }))
    .filter((entry) => entry.name && entry.slug)
    .sort((a, b) => b.name.length - a.name.length);
  if (entries.length === 0) return text;
  const nameMap = new Map(entries.map((entry) => [entry.name.toLowerCase(), entry]));
  const pattern = new RegExp(`\\b(${entries.map((e) => escapeRegExp(e.name)).join("|")})\\b`, "gi");
  const parts = text.split(pattern);
  return parts.map((part, idx) => {
    const match = nameMap.get(part.toLowerCase());
    if (!match) return <span key={`${part}-${idx}`}>{part}</span>;
    return (
      <Link
        key={`${match.slug}-${idx}`}
        href={`/books/${bookId}/characters/${match.slug}`}
        className="assistant-entity-link"
      >
        {part}
      </Link>
    );
  });
}

function formatSources(raw) {
  const list = Array.isArray(raw)
    ? Array.from(new Set(raw.filter((n) => Number.isFinite(n)).map((n) => Number(n))))
    : [];
  const sorted = list.sort((a, b) => a - b);
  if (sorted.length === 0) return "";
  return `Sources: chapters ${sorted.join(", ")}`;
}

function ChatMessage({ message, onAction, entities, bookId }) {
  const isAssistant = message.role === "assistant";
  const fullWidth = message.fullWidth === true;
  const sourcesLabel = formatSources(message.sources);
  const actions = Array.isArray(message.actions)
    ? message.actions.filter((action) => action && typeof action.label === "string")
    : [];
  const content = typeof message.content === "string" ? message.content : "";
  const linkedContent = isAssistant ? renderEntityLinks(content, entities, bookId) : content;
  const sections = message.sections || null;

  return (
    <div className={`assistant-message-row ${isAssistant ? "" : "assistant-align-end"}`}>
      <div
        className={`assistant-message ${
          isAssistant ? "assistant-message--assistant" : "assistant-message--user"
        } ${fullWidth ? "assistant-message--full" : ""}`}
      >
        {sections ? (
          <>
            <div className="assistant-section">
              <div className="assistant-section-title">Summary</div>
              <div className="assistant-section-body whitespace-pre-wrap">{linkedContent}</div>
            </div>
            {Array.isArray(sections.evidence) && sections.evidence.length > 0 ? (
              <div className="assistant-section">
                <div className="assistant-section-title">Evidence</div>
                <ul className="assistant-section-list">
                  {sections.evidence.map((item, index) => (
                    <li key={`${item}-${index}`}>{renderEntityLinks(item, entities, bookId)}</li>
                  ))}
                </ul>
              </div>
            ) : null}
            {Array.isArray(sections.relationships) && sections.relationships.length > 0 ? (
              <div className="assistant-section">
                <div className="assistant-section-title">Relationships</div>
                <ul className="assistant-section-list">
                  {sections.relationships.map((item, index) => (
                    <li key={`${item}-${index}`}>{renderEntityLinks(item, entities, bookId)}</li>
                  ))}
                </ul>
              </div>
            ) : null}
          </>
        ) : (
          <div className="whitespace-pre-wrap">{linkedContent}</div>
        )}
        {sourcesLabel ? <div className="assistant-sources">{sourcesLabel}</div> : null}
        {isAssistant && actions.length > 0 ? (
          <div className="assistant-actions">
            {actions.map((action) => (
              <button
                key={action.id || action.label}
                type="button"
                onClick={() => onAction && onAction(action)}
                className="assistant-action-button"
              >
                {action.label}
              </button>
            ))}
          </div>
        ) : null}
      </div>
    </div>
  );
}

function TypingIndicator() {
  return (
    <div className="flex justify-start">
      <div className="assistant-message assistant-message--user type-body text-[var(--color-secondary)]">
        Thinking...
      </div>
    </div>
  );
}

export default function BookAssistantChat({ bookId, qaState = null }) {
  const [messages, setMessages] = useState(() => [
    {
      id: safeId(),
      role: "assistant",
      fullWidth: true,
      content: `Hi! I am your Scriba assistant. I answer using only the notes you have saved for this book, up through your latest logged chapter.\n\nTry questions like:\n- Who is [character] again?\n- How are [character A] and [character B] connected?\n- Can you summarize what I have captured so far?\n\nIf your notes are thin, I will say that clearly and suggest what to capture next.`,
    },
  ]);
  const [inputValue, setInputValue] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [promptOpen, setPromptOpen] = useState(false);
  const [promptDraft, setPromptDraft] = useState(null);
  const [promptResponse, setPromptResponse] = useState("");
  const [promptError, setPromptError] = useState("");
  const [promptSaving, setPromptSaving] = useState(false);
  const [entities, setEntities] = useState([]);
  const [scopeChapter, setScopeChapter] = useState(null);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (!scrollRef.current) return;
    scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  useEffect(() => {
    let active = true;
    const loadEntities = async () => {
      try {
        const res = await fetch(`/api/characters?bookId=${encodeURIComponent(bookId)}`);
        if (!res.ok) return;
        const payload = await res.json();
        const list = Array.isArray(payload?.characters) ? payload.characters : [];
        if (active) {
          setEntities(list);
        }
      } catch {
        // ignore
      }
    };
    const loadScope = async () => {
      try {
        const res = await fetch(`/api/notes?bookId=${encodeURIComponent(bookId)}`);
        if (!res.ok) return;
        const payload = await res.json();
        const notes = Array.isArray(payload?.notes) ? payload.notes : [];
        const max = notes.reduce((acc, note) => {
          const chapter = Number(note?.chapter_number);
          if (Number.isFinite(chapter) && chapter > acc) return chapter;
          return acc;
        }, 0);
        if (active && max > 0) setScopeChapter(max);
      } catch {
        // ignore
      }
    };
    if (bookId && qaState !== "empty") {
      loadEntities();
      loadScope();
    }
    return () => {
      active = false;
    };
  }, [bookId, qaState]);

  const createEmptySummary = () => ({
    summary: [],
    characters: [],
    setting: [],
    relationships: [],
    reflections: [],
    extras: [],
  });

  const findLatestSummary = (notes, excludeId) => {
    if (!Array.isArray(notes)) return createEmptySummary();
    for (let idx = notes.length - 1; idx >= 0; idx -= 1) {
      const note = notes[idx];
      if (!note || note.id === excludeId) continue;
      const ai = note.ai_summary;
      if (ai && typeof ai === "object") {
        return ai;
      }
    }
    return createEmptySummary();
  };

  const upsertSummaryForPromptedNote = async (noteId, content, chapterNumber) => {
    const listRes = await fetch(
      `/api/notes?bookId=${encodeURIComponent(bookId)}&chapterNumber=${encodeURIComponent(chapterNumber)}`,
    );
    if (!listRes.ok) return;
    const listPayload = await listRes.json();
    const notes = Array.isArray(listPayload?.notes) ? listPayload.notes : [];
    const previousSummary = findLatestSummary(notes, noteId);

    const aiRes = await fetch("/api/ai-reply", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        content,
        summary: previousSummary,
        notes: notes.map((note) => ({
          id: note.id,
          content: note.content,
          createdAt: note.created_at,
        })),
      }),
    });
    if (!aiRes.ok) return;
    const aiPayload = await aiRes.json();
    if (!aiPayload?.summary) return;

    await fetch(`/api/notes/${noteId}/summary`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ aiSummary: aiPayload.summary }),
    });
  };

  const sendMessage = async () => {
    const trimmed = inputValue.trim();
    if (!trimmed || isLoading) return;

    const userMessage = { id: safeId(), role: "user", content: trimmed };
    setMessages((prev) => [...prev, userMessage]);
    setInputValue("");

    if (qaState === "empty") {
      setMessages((prev) => [
        ...prev,
        {
          id: safeId(),
          role: "assistant",
          fullWidth: true,
          content: "I do not have any chapter notes for this book yet. Add your first note and I can help right away.",
        },
      ]);
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const res = await fetch(`/api/books/${encodeURIComponent(bookId)}/assistant`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ question: trimmed }),
      });
      if (!res.ok) {
        let message = "Unable to reach the assistant right now.";
        try {
          const payload = await res.json();
          if (payload?.error) message = payload.error;
        } catch {
          // ignore
        }
        throw new Error(message);
      }
      const payload = await res.json();
      const answer = typeof payload?.answer === "string" ? payload.answer.trim() : "";
      const actions = Array.isArray(payload?.actions) ? payload.actions : [];
      const structured = payload?.structured && typeof payload.structured === "object" ? payload.structured : null;
      if (!answer && !(structured && typeof structured.summary === "string")) {
        throw new Error("The assistant did not return a reply.");
      }
      setMessages((prev) => [
        ...prev,
        {
          id: safeId(),
          role: "assistant",
          fullWidth: true,
          content: typeof structured?.summary === "string" ? structured.summary : answer,
          actions,
          sources: Array.isArray(payload?.sources) ? payload.sources : [],
          sections: structured
            ? {
                evidence: Array.isArray(structured?.evidence) ? structured.evidence : [],
                relationships: Array.isArray(structured?.relationships)
                  ? structured.relationships
                  : [],
              }
            : null,
        },
      ]);
      if (Number.isFinite(payload?.maxChapter)) {
        setScopeChapter(payload.maxChapter);
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : "Something went wrong.";
      setError(message);
      setMessages((prev) => [
        ...prev,
        {
          id: safeId(),
          role: "assistant",
          fullWidth: true,
          content: "I hit a snag while checking your notes. Try again in a moment.",
        },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    void sendMessage();
  };

  const handleKeyDown = (event) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      void sendMessage();
    }
  };

  const handleAction = (action) => {
    if (!action || action.id !== "prompt-note") return;
    setPromptDraft(action);
    setPromptResponse("");
    setPromptError("");
    setPromptOpen(true);
  };

  const handlePromptSave = async () => {
    if (!promptDraft) return;
    const trimmed = promptResponse.trim();
    if (!trimmed) {
      setPromptError("Please add a quick note before saving.");
      return;
    }
    setPromptSaving(true);
    setPromptError("");
    try {
      const res = await fetch(`/api/books/${encodeURIComponent(bookId)}/prompted-notes`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          chapterNumber: promptDraft.chapterNumber,
          content: trimmed,
          prompt: {
            title: promptDraft?.prompt?.title,
            context: promptDraft?.prompt?.context,
            questions: promptDraft?.prompt?.questions,
            topic: promptDraft?.topic,
          },
        }),
      });
      if (!res.ok) {
        let message = "Unable to save that note.";
        try {
          const payload = await res.json();
          if (payload?.error) message = payload.error;
        } catch {
          // ignore
        }
        throw new Error(message);
      }
      const payload = await res.json();
      if (payload?.noteId) {
        await upsertSummaryForPromptedNote(payload.noteId, trimmed, promptDraft.chapterNumber);
      }
      setMessages((prev) => [
        ...prev,
        {
          id: safeId(),
          role: "assistant",
          fullWidth: true,
          content: "Got it. I added that to your notes and folded it into the book memory.",
        },
      ]);
      setPromptOpen(false);
    } catch (err) {
      const message = err instanceof Error ? err.message : "Unable to save that note.";
      setPromptError(message);
    } finally {
      setPromptSaving(false);
    }
  };

  return (
    <div className="assistant-chat">
      <div ref={scrollRef} className="assistant-scroll">
        <div className="assistant-scroll-inner">
          {scopeChapter ? (
            <div className="assistant-scope">Using notes up through chapter {scopeChapter}</div>
          ) : (
            <div className="assistant-scope">No chapter notes yet. Add a note and I can help you review it.</div>
          )}
          {messages.map((message) => (
            <ChatMessage
              key={message.id}
              message={message}
              onAction={handleAction}
              entities={entities}
              bookId={bookId}
            />
          ))}
          {isLoading ? <TypingIndicator /> : null}
        </div>
      </div>
      <form onSubmit={handleSubmit} className="assistant-input-bar">
        <div className="assistant-input-inner">
          {error ? <div className="type-caption mb-2 text-red-500">{error}</div> : null}
          <div className="assistant-input-row">
            <textarea
              value={inputValue}
              onChange={(event) => setInputValue(event.target.value)}
              onKeyDown={handleKeyDown}
              rows={1}
              placeholder="Ask about your notes, characters, places, or moments"
              className="assistant-textarea"
              disabled={isLoading}
            />
            <button
              type="submit"
              className="assistant-send"
              disabled={isLoading || !inputValue.trim()}
              aria-label="Send question"
            >
              <svg className="h-4 w-4" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path
                  d="M3.75 3.75l12.5 6.25-12.5 6.25 2.5-6.25-2.5-6.25z"
                  stroke="currentColor"
                  strokeWidth="1.4"
                  strokeLinejoin="round"
                />
              </svg>
            </button>
          </div>
        </div>
      </form>

      {promptOpen ? (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/40 p-4 sm:items-center">
          <div className="w-full max-w-lg rounded-2xl bg-[var(--color-page)] p-5 text-[var(--color-text-main)] shadow-xl">
            <div className="type-body text-[var(--color-secondary)]">Prompted note</div>
            <div className="type-h3 mt-1">
              {promptDraft?.prompt?.title || "Add a note"}
            </div>
            {promptDraft?.chapterNumber ? (
              <div className="type-caption mt-1 text-[var(--color-secondary)]">
                Chapter {promptDraft.chapterNumber}
              </div>
            ) : null}

            {promptDraft?.prompt?.context ? (
              <div className="type-body mt-3 rounded-xl bg-[var(--color-surface)] p-3 text-[var(--color-secondary)]">
                {promptDraft.prompt.context}
              </div>
            ) : null}

            {Array.isArray(promptDraft?.prompt?.questions) && promptDraft.prompt.questions.length > 0 ? (
              <div className="type-body mt-4 space-y-2">
                {promptDraft.prompt.questions.map((question, index) => (
                  <div key={`${question}-${index}`} className="flex items-start gap-2">
                    <span className="mt-2 h-1.5 w-1.5 shrink-0 rounded-full bg-[var(--color-accent)]" />
                    <span>{question}</span>
                  </div>
                ))}
              </div>
            ) : null}

            <div className="mt-4 rounded-xl bg-[var(--color-surface)] px-3 py-2">
              <textarea
                value={promptResponse}
                onChange={(event) => setPromptResponse(event.target.value)}
                rows={4}
                placeholder="Write a few lines..."
                className="type-body w-full resize-none bg-transparent text-[var(--color-text-main)] outline-none placeholder:text-[var(--color-text-disabled)]"
              />
            </div>

            {promptError ? <div className="type-caption mt-2 text-red-500">{promptError}</div> : null}

            <div className="mt-4 flex items-center justify-end gap-2">
              <button
                type="button"
                onClick={() => setPromptOpen(false)}
                className="type-button rounded-full px-4 py-2 text-[var(--color-secondary)]"
                disabled={promptSaving}
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={handlePromptSave}
                className="type-button rounded-full bg-[var(--color-accent)] px-4 py-2 text-[var(--color-text-on-accent)] transition hover:bg-[var(--color-accent-hover)] disabled:cursor-not-allowed disabled:opacity-60"
                disabled={promptSaving}
              >
                {promptSaving ? "Saving..." : "Save note"}
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
}
